/**
 * Search templates by category, tags, character count, and/or keyword.
 * Supports sorting by popularity, rating, or newest (highest id suffix).
 */
export function searchTemplates(options = {}) {
    let results = [...TEMPLATES];
    if (options.category) {
        results = results.filter((t) => t.category === options.category);
    }
    if (options.tags && options.tags.length > 0) {
        results = results.filter((t) => options.tags.every((tag) => t.tags.includes(tag)));
    }
    if (options.characterCount) {
        results = results.filter((t) => t.characterCount === options.characterCount);
    }
    if (options.keyword) {
        const kw = options.keyword.toLowerCase();
        results = results.filter((t) => t.title.toLowerCase().includes(kw) ||
            t.description.toLowerCase().includes(kw) ||
            t.visualPrompt.toLowerCase().includes(kw) ||
            (t.actingPrompt?.toLowerCase().includes(kw) ?? false));
    }
    switch (options.sortBy) {
        case "popular":
            results.sort((a, b) => (b.usageCount ?? 0) - (a.usageCount ?? 0));
            break;
        case "rating":
            results.sort((a, b) => (b.rating ?? 0) - (a.rating ?? 0));
            break;
        case "newest":
            results.sort((a, b) => b.id.localeCompare(a.id));
            break;
        default:
            results.sort((a, b) => (b.usageCount ?? 0) - (a.usageCount ?? 0));
    }
    if (options.limit && options.limit > 0) {
        results = results.slice(0, options.limit);
    }
    return results;
}
